'use client';

import { type UseMutationResult } from '@tanstack/react-query';
import { useState, useMemo, useCallback, useEffect, type Dispatch, type SetStateAction } from 'react';

import { useAuth } from '@/features/auth/context/AuthContext';
import {
  useAuthUsers,
  useAuthUserSecurity,
  useMockSignIn,
  useRegisterUser,
  useDeleteAuthUser,
  useUpdateAuthUser,
  useUpdateAuthUserSecurity,
  useUpdateAuthUserRoles,
} from '@/features/auth/hooks/useAuthQueries';
import { type AuthUserRoleMap } from '@/features/auth/utils/auth-management';
import type {
  RegisterResponse,
  AuthUserSecurityProfile,
  AuthUser as AuthUserSummary,
  AuthRole,
} from '@/shared/contracts/auth';
import { useToast } from '@/shared/ui/primitives.public';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


type CreateUserForm = {
  name: string;
  email: string;
  password: string;
  roleId: string;
  verified: boolean;
};
const EMPTY_CREATE: CreateUserForm = {
  name: '',
  email: '',
  password: '',
  roleId: 'none',
  verified: false,
};

export interface UseUsersStateReturn {
  users: AuthUserSummary[];
  filteredUsers: AuthUserSummary[];
  search: string;
  setSearch: (query: string) => void;
  localUserRoles: AuthUserRoleMap;
  handleRoleChange: (userId: string, roleId: string) => void;
  dirtyRoles: boolean;
  saveRoles: () => Promise<void>;
  editingUser: AuthUserSummary | null;
  setEditingUser: Dispatch<SetStateAction<AuthUserSummary | null>>;
  userToDelete: AuthUserSummary | null;
  setUserToDelete: Dispatch<SetStateAction<AuthUserSummary | null>>;
  deleteUser: () => Promise<void>;
  createOpen: boolean;
  setCreateOpen: Dispatch<SetStateAction<boolean>>;
  createForm: CreateUserForm;
  setCreateForm: Dispatch<SetStateAction<CreateUserForm>>;
  mockOpen: boolean;
  setMockOpen: Dispatch<SetStateAction<boolean>>;
  mockEmail: string;
  setMockEmail: (email: string) => void;
  mockPassword: string;
  setMockPassword: (password: string) => void;
  isLoading: boolean;
  isFetching: boolean;
  canReadUsers: boolean;
  canManageSecurity: boolean;
  roles: AuthRole[];
  provider: string;
  refetch: () => void;
  userSecurity: AuthUserSecurityProfile | undefined;
  loadingSecurity: boolean;
  mutations: {
    updateUser: UseMutationResult<
      AuthUserSummary,
      Error,
      {
        userId: string;
        input: { name?: string | null; email?: string | null; emailVerified?: boolean | null };
      }
    >;
    updateSecurity: UseMutationResult<
      AuthUserSecurityProfile,
      Error,
      {
        userId: string;
        input: {
          disabled?: boolean;
          banned?: boolean;
          allowedIps?: string[];
          disableMfa?: boolean;
        };
      }
    >;
    deleteUser: UseMutationResult<{ id: string; deleted: boolean }, Error, { userId: string }>;
    register: UseMutationResult<
      { ok: boolean; payload: RegisterResponse },
      Error,
      {
        email: string;
        password: string;
        name?: string | undefined;
        emailVerified?: boolean | undefined;
      }
    >;
    mockSignIn: UseMutationResult<
      { ok: boolean; payload: { ok?: boolean; message?: string } },
      Error,
      { email: string; password: string }
    >;
  };
}

export function useUsersState(): UseUsersStateReturn {
  const { toast } = useToast();
  const {
    session,
    roles,
    userRoles,
    canReadUsers,
    canManageSecurity,
    isLoading: authLoading,
    refetchSettings,
  } = useAuth();

  const [localUserRoles, setLocalUserRoles] = useState<AuthUserRoleMap>({});
  const [search, setSearch] = useState('');
  const [dirtyRoles, setDirtyRoles] = useState(false);
  const [editingUser, setEditingUser] = useState<AuthUserSummary | null>(null);
  const [userToDelete, setUserToDelete] = useState<AuthUserSummary | null>(null);

  const [createOpen, setCreateOpen] = useState(false);
  const [createForm, setCreateForm] = useState<CreateUserForm>(EMPTY_CREATE);

  const [mockOpen, setMockOpen] = useState(false);
  const [mockEmail, setMockEmail] = useState('');
  const [mockPassword, setMockPassword] = useState('');

  const authUsersQuery = useAuthUsers(canReadUsers);
  const userSecurityQuery = useAuthUserSecurity(canManageSecurity ? editingUser?.id : null);

  const updateAuthUserMutation = useUpdateAuthUser();
  const updateAuthUserSecurityMutation = useUpdateAuthUserSecurity();
  const deleteAuthUserMutation = useDeleteAuthUser();
  const registerUserMutation = useRegisterUser();
  const mockSignInMutation = useMockSignIn();
  const updateUserRolesMutation = useUpdateAuthUserRoles();

  useEffect(() => {
    setLocalUserRoles(userRoles);
    setDirtyRoles(false);
  }, [userRoles]);

  const users = authUsersQuery.data?.users ?? [];
  const filteredUsers = useMemo(() => {
    const q = search.trim().toLowerCase();
    if (!q) return users;
    return users.filter(
      (u) =>
        u.email?.toLowerCase().includes(q) ||
        u.name?.toLowerCase().includes(q) ||
        u.id.toLowerCase().includes(q)
    );
  }, [users, search]);

  const handleRoleChange = useCallback((userId: string, roleId: string) => {
    setLocalUserRoles((prev) => {
      const next = { ...prev };
      if (!roleId || roleId === 'none') delete next[userId];
      else next[userId] = roleId;
      return next;
    });
    setDirtyRoles(true);
  }, []);

  const saveRoles = async () => {
    try {
      await updateUserRolesMutation.mutateAsync({ userRoles: localUserRoles });
      setDirtyRoles(false);
      toast('User roles updated', { variant: 'success' });
    } catch (_e) {
      logClientError(_e);
      toast('Failed to save roles', { variant: 'error' });
    }
  };

  const deleteUser = async () => {
    if (!userToDelete) return;
    if (session?.user?.id && userToDelete.id === session.user.id) {
      toast('You cannot delete your own account while signed in.', { variant: 'error' });
      return;
    }
    try {
      await deleteAuthUserMutation.mutateAsync({ userId: userToDelete.id });
      toast('User deleted', { variant: 'success' });
      setUserToDelete(null);
    } catch (error) {
      logClientError(error);
      const message =
        error instanceof Error && error.message.trim()
          ? error.message
          : 'Failed to delete user';
      toast(message, { variant: 'error' });
    }
  };

  return {
    users,
    filteredUsers,
    search,
    setSearch,
    localUserRoles,
    handleRoleChange,
    dirtyRoles,
    saveRoles,
    editingUser,
    setEditingUser,
    userToDelete,
    setUserToDelete,
    deleteUser,
    createOpen,
    setCreateOpen,
    createForm,
    setCreateForm,
    mockOpen,
    setMockOpen,
    mockEmail,
    setMockEmail,
    mockPassword,
    setMockPassword,
    isLoading: authUsersQuery.isPending || authLoading,
    isFetching: authUsersQuery.isFetching,
    canReadUsers,
    canManageSecurity,
    roles,
    provider: authUsersQuery.data?.provider ?? 'mongodb',
    refetch: () => {
      void authUsersQuery.refetch();
      void refetchSettings();
    },
    userSecurity: userSecurityQuery.data,
    loadingSecurity: userSecurityQuery.isPending,
    mutations: {
      updateUser: updateAuthUserMutation,
      updateSecurity: updateAuthUserSecurityMutation,
      deleteUser: deleteAuthUserMutation,
      register: registerUserMutation,
      mockSignIn: mockSignInMutation,
    },
  };
}

'use client';

import React, { useEffect, useMemo } from 'react';

import { useAuth } from '@/features/auth/context/AuthContext';
import { useAuthUsers } from '@/features/auth/hooks/useAuthQueries';
import type { AuthRole } from '@/features/auth/utils/auth-management';
import type { AuthUser as AuthUserSummary } from '@/shared/contracts/auth';
import { Card, CardContent, CardDescription, CardHeader, CardTitle, useToast, Alert } from '@/shared/ui/primitives.public';
import { SectionHeader, MetadataItem, LoadingState, UI_GRID_RELAXED_CLASSNAME } from '@/shared/ui/navigation-and-layout.public';
import { logClientError } from '@/shared/utils/observability/client-error-logger';

export default function AuthDashboardPage(): React.JSX.Element {
  const { toast } = useToast();
  const { roles, userRoles, canReadUsers, isLoading: authLoading } = useAuth();

  const authUsersQuery = useAuthUsers(canReadUsers);

  useEffect(() => {
    if (!authUsersQuery.error || !canReadUsers) return;
    logClientError(authUsersQuery.error, {
      context: { source: 'AuthDashboardPage', action: 'loadMetrics' },
    });
    toast('Failed to load auth dashboard data', { variant: 'error' });
  }, [authUsersQuery.error, toast, canReadUsers]);

  const users = useMemo<AuthUserSummary[]>(
    () => (canReadUsers ? (authUsersQuery.data?.users ?? []) : []),
    [authUsersQuery.data?.users, canReadUsers]
  );
  const provider = authUsersQuery.data?.provider ?? 'mongodb';

  const metrics = useMemo(() => {
    const total = users.length;
    const verified = users.filter((user: AuthUserSummary) => Boolean(user.emailVerified)).length;
    const unverified = total - verified;
    const roleCounts = roles.reduce<Record<string, number>>(
      (acc: Record<string, number>, role: AuthRole) => {
        acc[role.id] = 0;
        return acc;
      },
      {}
    );
    let unassigned = 0;
    users.forEach((user: AuthUserSummary) => {
      const assignedRole = userRoles[user.id];
      if (assignedRole && roleCounts[assignedRole] !== undefined) {
        roleCounts[assignedRole] += 1;
      } else {
        unassigned += 1;
      }
    });
    return { total, verified, unverified, roleCounts, unassigned };
  }, [roles, userRoles, users]);

  if (!canReadUsers) {
    return (
      <div className='page-section'>
        <Alert variant='warning' className='p-6 text-sm'>
          You don&apos;t have permission to view auth metrics. Ask an admin to grant
          `auth.users.read` or elevate your account.
        </Alert>
      </div>
    );
  }

  if (authUsersQuery.isPending || authLoading) {
    return (
      <div className='page-section'>
        <Card variant='glass' padding='lg' className='flex justify-center'>
          <LoadingState message='Loading auth metrics...' />
        </Card>
      </div>
    );
  }

  return (
    <div className='page-section max-w-5xl space-y-6'>
      <Card variant='glass' padding='lg'>
        <SectionHeader
          title='Auth Dashboard'
          description={`Overview of user accounts and role assignments (provider: ${provider}).`}
        />
      </Card>

      <div className={`${UI_GRID_RELAXED_CLASSNAME} sm:grid-cols-2 lg:grid-cols-4`}>
        <MetadataItem
          label='Total Users'
          hint='All accounts'
          value={String(metrics.total)}
          valueClassName='text-3xl font-semibold text-white'
          className='p-4'
        />
        <MetadataItem
          label='Verified Emails'
          hint='Email verified'
          value={String(metrics.verified)}
          valueClassName='text-3xl font-semibold text-white'
          className='p-4'
        />
        <MetadataItem
          label='Unverified'
          hint='Pending verification'
          value={String(metrics.unverified)}
          valueClassName='text-3xl font-semibold text-white'
          className='p-4'
        />
        <MetadataItem
          label='Unassigned Roles'
          hint='No role assigned'
          value={String(metrics.unassigned)}
          valueClassName='text-3xl font-semibold text-white'
          className='p-4'
        />
      </div>

      <Card className='bg-card border-border'>
        <CardHeader>
          <CardTitle className='text-white text-lg'>Role Distribution</CardTitle>
          <CardDescription className='text-gray-500'>Users assigned to each role.</CardDescription>
        </CardHeader>
        <CardContent className='grid gap-3 sm:grid-cols-2 lg:grid-cols-3'>
          {roles.map((role: AuthRole) => (
            <MetadataItem
              key={role.id}
              label={role.name}
              hint={role.description ?? role.id}
              value={String(metrics.roleCounts[role.id] ?? 0)}
              valueClassName='text-2xl font-semibold text-white'
              className='p-4 bg-card/50'
            />
          ))}
        </CardContent>
      </Card>
    </div>
  );
}

'use client';

import { ActivityIcon } from 'lucide-react';
import type { ColumnDef } from '@tanstack/react-table';
import React, { useDeferredValue, useEffect, useMemo, useState } from 'react';

import { ActivityTypes } from '@/shared/constants/observability';
import type { ActivityLog } from '@/shared/contracts/system';
import { useSystemActivity } from '@/shared/hooks/useSystemActivity';
import { EmptyState, PageLayout, Pagination, UI_CENTER_ROW_RELAXED_CLASSNAME } from '@/shared/ui/navigation-and-layout.public';
import { SearchInput } from '@/shared/ui/forms-and-actions.public';
import { StandardDataTablePanel } from '@/shared/ui/templates.public';
import { StatusBadge } from '@/shared/ui/data-display.public';
import { formatDateTime } from '@/shared/utils/formatting';

const PAGE_SIZE = 25;
const LOGIN_DESCRIPTION_PREFIX = 'User logged in:';

const readLoginIdentity = (log: ActivityLog): string => {
  if (log.description.startsWith(LOGIN_DESCRIPTION_PREFIX)) {
    const identity = log.description.slice(LOGIN_DESCRIPTION_PREFIX.length).trim();
    if (identity) return identity;
  }

  return log.description || 'Unknown account';
};

const readMetadataText = (log: ActivityLog, key: string): string | null => {
  const value = log.metadata?.[key];
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  return trimmed ? trimmed : null;
};

export default function AuthLoginActivityPage(): React.JSX.Element {
  const [page, setPage] = useState(1);
  const [search, setSearch] = useState('');
  const deferredSearch = useDeferredValue(search.trim());

  useEffect(() => {
    setPage(1);
  }, [deferredSearch]);

  const query = useSystemActivity({
    page,
    pageSize: PAGE_SIZE,
    search: deferredSearch || undefined,
    type: ActivityTypes.AUTH.LOGIN,
  });

  const activity = query.data?.data ?? [];
  const total = query.data?.total ?? 0;

  const columns = useMemo<ColumnDef<ActivityLog>[]>(
    () => [
      {
        id: 'identity',
        header: 'User',
        cell: ({ row }) => (
          <div className='flex flex-col'>
            <span className='font-medium text-gray-200'>{readLoginIdentity(row.original)}</span>
            <span className='font-mono text-[10px] text-gray-500'>
              {row.original.userId ?? 'unknown-user'}
            </span>
          </div>
        ),
      },
      {
        id: 'context',
        header: 'Context',
        cell: ({ row }) => {
          const surface = readMetadataText(row.original, 'surface');
          const authFlow = readMetadataText(row.original, 'authFlow');
          const loginMethod = readMetadataText(row.original, 'loginMethod');

          return (
            <div className='flex flex-col gap-2'>
              <div className='flex flex-wrap gap-1.5'>
                <StatusBadge
                  status={surface === 'kangur' ? 'Kangur' : 'Main App'}
                  variant={surface === 'kangur' ? 'info' : 'neutral'}
                  size='sm'
                />
                {loginMethod ? (
                  <StatusBadge status={loginMethod} variant='neutral' size='sm' className='font-mono' />
                ) : null}
                {authFlow ? (
                  <StatusBadge status={authFlow} variant='neutral' size='sm' className='font-mono' />
                ) : null}
              </div>
              <span className='text-xs text-gray-500'>{row.original.description}</span>
            </div>
          );
        },
      },
      {
        accessorKey: 'createdAt',
        header: 'Logged In',
        cell: ({ row }) => (
          <span className='font-mono text-xs text-gray-500'>
            {formatDateTime(row.original.createdAt)}
          </span>
        ),
      },
    ],
    []
  );

  return (
    <PageLayout
      title='Login Activity'
      description='Review successful auth sign-ins recorded across the application.'
      icon={<ActivityIcon className='size-4' />}
      refresh={{
        onRefresh: () => {
          void query.refetch();
        },
        isRefreshing: query.isFetching,
      }}
      containerClassName='mx-auto w-full max-w-none py-10'
    >
      <StandardDataTablePanel
        columns={columns}
        data={activity}
        isLoading={query.isLoading}
        filters={
          <div className={UI_CENTER_ROW_RELAXED_CLASSNAME}>
            <div className='max-w-sm flex-1'>
              <SearchInput
                value={search}
                onChange={(event) => setSearch(event.target.value)}
                onClear={() => setSearch('')}
                placeholder='Search login activity...'
                size='sm'
              />
            </div>
            <StatusBadge
              status={`${total} login${total === 1 ? '' : 's'}`}
              variant='info'
              className='py-1'
            />
          </div>
        }
        footer={
          <Pagination
            page={page}
            totalCount={total}
            pageSize={PAGE_SIZE}
            onPageChange={setPage}
            showInfo={true}
            variant='compact'
            isLoading={query.isFetching}
          />
        }
        emptyState={
          <EmptyState
            title={deferredSearch ? 'No matching logins found' : 'No login activity yet'}
            description={
              deferredSearch
                ? 'Try a different email address, user identifier, or keyword.'
                : 'Successful sign-ins will appear here once users start logging in.'
            }
          />
        }
      />
    </PageLayout>
  );
}

