import 'server-only';

import { hash } from 'bcryptjs';

import type { AuthUserRecord } from '@/shared/contracts/auth';
import { conflictError } from '@/shared/errors/app-error';
import { getAuthDataProvider, requireAuthProvider } from '@/shared/lib/auth/services/auth-provider';
import { getMongoDb } from '@/shared/lib/db/mongo-client';

import { findAuthUserByEmail, findAuthUserById, normalizeAuthEmail } from './auth-user-repository';

type MongoUserDoc = {
  email: string;
  name?: string | null;
  passwordHash?: string | null;
  emailVerified?: Date | null;
  image?: string | null;
  createdAt: Date;
  updatedAt: Date;
};

const AUTH_USERS_COLLECTION = 'users';
const AUTH_USERS_EMAIL_UNIQUE_INDEX = 'auth_users_email_unique';

const normalizeOptionalName = (value: string | null | undefined): string | null => {
  if (typeof value !== 'string') {
    return null;
  }

  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : null;
};

const isMongoDuplicateKeyError = (error: unknown): boolean => {
  const code =
    typeof error === 'object' && error !== null && 'code' in error
      ? (error as { code?: unknown }).code
      : null;
  const message =
    error instanceof Error
      ? error.message.toLowerCase()
      : typeof error === 'string'
        ? error.toLowerCase()
        : '';
  return code === 11000 || message.includes('e11000') || message.includes('duplicate key');
};

const getMongoUsersCollection = async () =>
  (await getMongoDb()).collection<MongoUserDoc>(AUTH_USERS_COLLECTION);

let ensureMongoAuthUserIndexesPromise: Promise<void> | null = null;

const ensureMongoAuthUserIndexes = async (): Promise<void> => {
  if (!ensureMongoAuthUserIndexesPromise) {
    ensureMongoAuthUserIndexesPromise = (async () => {
      const collection = await getMongoUsersCollection();
      await collection.createIndex(
        { email: 1 },
        {
          name: AUTH_USERS_EMAIL_UNIQUE_INDEX,
          unique: true,
          partialFilterExpression: { email: { $type: 'string' } },
        }
      );
    })().catch((error) => {
      ensureMongoAuthUserIndexesPromise = null;
      throw error;
    });
  }

  return ensureMongoAuthUserIndexesPromise;
};

export const createAuthUserWithEmail = async (input: {
  email: string;
  name?: string | null;
  passwordHash?: string | null;
  emailVerified?: Date | null;
  duplicateErrorMessage?: string;
}): Promise<AuthUserRecord> => {
  const email = normalizeAuthEmail(input.email);
  const provider = requireAuthProvider(await getAuthDataProvider());
  const normalizedName = normalizeOptionalName(input.name);
  const passwordHash = input.passwordHash ?? null;
  const emailVerified = input.emailVerified ?? null;
  const duplicateErrorMessage = input.duplicateErrorMessage;
  void provider;

  if (!process.env['MONGODB_URI']) {
    throw new Error('MongoDB is not configured.');
  }

  const now = new Date();
  const collection = await getMongoUsersCollection();
  await ensureMongoAuthUserIndexes();
  try {
    const result = await collection.insertOne({
      email,
      name: normalizedName,
      passwordHash,
      emailVerified,
      image: null,
      createdAt: now,
      updatedAt: now,
    });

    return {
      id: result.insertedId.toString(),
      email,
      name: normalizedName,
      passwordHash,
      image: null,
      emailVerified,
    };
  } catch (error) {
    if (isMongoDuplicateKeyError(error)) {
      throw conflictError(duplicateErrorMessage ?? 'User already exists.', { email });
    }
    throw error;
  }
};

export const ensureAuthUserWithEmail = async (input: {
  email: string;
  name?: string | null;
}): Promise<{ user: AuthUserRecord; created: boolean }> => {
  const existing = await findAuthUserByEmail(input.email);
  if (existing) {
    return {
      user: existing,
      created: false,
    };
  }

  const created = await createAuthUserWithEmail({
    email: input.email,
    name: input.name,
    passwordHash: null,
    emailVerified: null,
  });

  return {
    user: created,
    created: true,
  };
};

export const markAuthUserEmailVerified = async (userId: string): Promise<AuthUserRecord | null> => {
  requireAuthProvider(await getAuthDataProvider());
  const verifiedAt = new Date();

  if (!process.env['MONGODB_URI']) {
    return null;
  }

  const mongo = await getMongoDb();
  const { ObjectId } = await import('mongodb');
  if (!ObjectId.isValid(userId)) {
    return null;
  }

  await mongo.collection<MongoUserDoc>('users').updateOne(
    { _id: new ObjectId(userId) },
    {
      $set: {
        emailVerified: verifiedAt,
        updatedAt: verifiedAt,
      },
    }
  );

  return findAuthUserById(userId);
};

export const setAuthUserPassword = async (
  userId: string,
  password: string
): Promise<AuthUserRecord | null> => {
  requireAuthProvider(await getAuthDataProvider());
  const passwordHash = await hash(password, 12);

  if (!process.env['MONGODB_URI']) {
    return null;
  }

  const mongo = await getMongoDb();
  const { ObjectId } = await import('mongodb');
  if (!ObjectId.isValid(userId)) {
    return null;
  }

  await mongo.collection<MongoUserDoc>('users').updateOne(
    { _id: new ObjectId(userId) },
    {
      $set: {
        passwordHash,
        updatedAt: new Date(),
      },
    }
  );

  return findAuthUserById(userId);
};

import { 
  DEFAULT_AUTH_SECURITY_POLICY, 
  normalizeAuthSecurityPolicy, 
  type AuthSecurityPolicy 
} from '@/features/auth/utils/auth-security';
import { AUTH_SETTINGS_KEYS } from '@/features/auth/utils/auth-management';
import { parseJsonSetting } from '@/shared/utils/settings-json';
import { requireAuthProvider, getAuthDataProvider } from '@/shared/lib/auth/services/auth-provider';
import { getMongoDb } from '@/shared/lib/db/mongo-client';
import { type MongoSettingRecord } from '@/shared/contracts/base';

const readMongoSetting = async (key: string): Promise<string | null> => {
  if (!process.env['MONGODB_URI']) return null;
  const mongo = await getMongoDb();
  const doc = await mongo
    .collection<MongoSettingRecord>('settings')
    .findOne({ $or: [{ _id: key }, { key }] });
  return typeof doc?.value === 'string' ? doc.value : null;
};

const readSettingValue = async (key: string): Promise<string | null> => {
  requireAuthProvider(await getAuthDataProvider());
  return readMongoSetting(key);
};

export const getAuthSecurityPolicy = async (): Promise<AuthSecurityPolicy> => {
  const storedPolicyValue = await readSettingValue(AUTH_SETTINGS_KEYS.securityPolicy);
  if (storedPolicyValue) {
    const parsed = parseJsonSetting<AuthSecurityPolicy>(
      storedPolicyValue,
      DEFAULT_AUTH_SECURITY_POLICY
    );
    return normalizeAuthSecurityPolicy(parsed);
  }

  return DEFAULT_AUTH_SECURITY_POLICY;
};

import { type AuthSecurityPolicy } from '@/features/auth/utils/auth-security';

export const validatePasswordStrength = (
  password: string,
  policy: AuthSecurityPolicy
): { ok: boolean; errors: string[] } => {
  const errors: string[] = [];
  if (password.length < policy.minPasswordLength) {
    errors.push(`Password must be at least ${policy.minPasswordLength} characters.`);
  }

  if (policy.requireStrongPassword) {
    if (policy.requireUppercase && !/[A-Z]/.test(password)) {
      errors.push('Password must include at least one uppercase letter.');
    }
    if (policy.requireLowercase && !/[a-z]/.test(password)) {
      errors.push('Password must include at least one lowercase letter.');
    }
    if (policy.requireNumber && !/[0-9]/.test(password)) {
      errors.push('Password must include at least one number.');
    }
    if (policy.requireSymbol && !/[^A-Za-z0-9]/.test(password)) {
      errors.push('Password must include at least one symbol.');
    }
  }

  return { ok: errors.length === 0, errors };
};

import 'server-only';

import crypto from 'crypto';

const ALPHABET = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ234567';

const base32Encode = (buffer: Buffer): string => {
  let bits = 0;
  let value = 0;
  let output = '';
  for (const byte of buffer) {
    value = (value << 8) | byte;
    bits += 8;
    while (bits >= 5) {
      output += ALPHABET[(value >>> (bits - 5)) & 31];
      bits -= 5;
    }
  }
  if (bits > 0) {
    output += ALPHABET[(value << (5 - bits)) & 31];
  }
  return output;
};

const base32Decode = (input: string): Buffer => {
  const clean = input.toUpperCase().replace(/[^A-Z2-7]/g, '');
  let bits = 0;
  let value = 0;
  const output: number[] = [];
  for (const char of clean) {
    const idx = ALPHABET.indexOf(char);
    if (idx === -1) continue;
    value = (value << 5) | idx;
    bits += 5;
    if (bits >= 8) {
      output.push((value >>> (bits - 8)) & 0xff);
      bits -= 8;
    }
  }
  return Buffer.from(output);
};

export const generateTotpSecret = (): string => {
  const buffer = crypto.randomBytes(20);
  return base32Encode(buffer);
};

export const buildOtpAuthUrl = (params: {
  secret: string;
  label: string;
  issuer: string;
}): string => {
  const label = encodeURIComponent(params.label);
  const issuer = encodeURIComponent(params.issuer);
  return `otpauth://totp/${label}?secret=${params.secret}&issuer=${issuer}`;
};

const generateTotp = (
  secret: string,
  timestamp: number,
  digits: number = 6,
  step: number = 30
): string => {
  const counter = Math.floor(timestamp / 1000 / step);
  const buffer = Buffer.alloc(8);
  buffer.writeBigInt64BE(BigInt(counter));
  const key = base32Decode(secret);
  const hmac = crypto.createHmac('sha1', key).update(buffer).digest();
  const offset = hmac[hmac.length - 1]! & 0x0f;
  const code =
    ((hmac[offset]! & 0x7f) << 24) |
    ((hmac[offset + 1]! & 0xff) << 16) |
    ((hmac[offset + 2]! & 0xff) << 8) |
    (hmac[offset + 3]! & 0xff);
  const otp = (code % 10 ** digits).toString().padStart(digits, '0');
  return otp;
};

export const verifyTotpToken = (secret: string, token: string, window: number = 1): boolean => {
  const clean = token.replace(/\s+/g, '');
  const now = Date.now();
  for (let offset = -window; offset <= window; offset += 1) {
    const ts = now + offset * 30 * 1000;
    if (generateTotp(secret, ts) === clean) {
      return true;
    }
  }
  return false;
};

export const generateRecoveryCodes = (count: number = 8): string[] => {
  return Array.from({ length: count }, (): string => {
    const raw = crypto.randomBytes(6).toString('hex').toUpperCase();
    return `${raw.slice(0, 4)}-${raw.slice(4, 8)}-${raw.slice(8, 12)}`;
  });
};

export const normalizeRecoveryCode = (code: string): string =>
  code.toUpperCase().replace(/[^A-Z0-9]/g, '');

export const hashRecoveryCode = (code: string): string => {
  const normalized = normalizeRecoveryCode(code);
  return crypto.createHash('sha256').update(normalized).digest('hex');
};

import 'server-only';

import { ObjectId } from 'mongodb';

import {
  type UserPreferences,
  type UserPreferencesUpdate as UserPreferencesData,
} from '@/shared/contracts/auth';
import type { JsonValue } from '@/shared/contracts/json';
import { operationFailedError } from '@/shared/errors/app-error';
import { getMongoDb } from '@/shared/lib/db/mongo-client';

const toMongoId = (id: string): ObjectId | string => {
  if (ObjectId.isValid(id) && id.length === 24) return new ObjectId(id);
  return id;
};

const parsePositiveInt = (value: string | undefined, fallback: number): number => {
  const parsed = Number(value);
  return Number.isFinite(parsed) && parsed > 0 ? Math.floor(parsed) : fallback;
};

export type UserPreferencesRecord = UserPreferences;

type UserPreferencesDocument = {
  _id: string | ObjectId;
  userId: string;
  productListNameLocale: string | null;
  productListCatalogFilter: string | null;
  productListCurrencyCode: string | null;
  productListPageSize: number | null;
  productListThumbnailSource: 'file' | 'link' | 'base64' | null;
  productListFiltersCollapsedByDefault: boolean | null;
  productListShowTriggerRunFeedback: boolean | null;
  productListAdvancedFilterPresets: UserPreferences['productListAdvancedFilterPresets'] | null;
  productListAppliedAdvancedFilter: string | null;
  productListAppliedAdvancedFilterPresetId: string | null;
  productListDraftIconColorMode: 'theme' | 'custom' | null;
  productListDraftIconColor: string | null;
  aiPathsActivePathId: string | null;
  imageStudioLastProjectId: string | null;
  caseResolverCaseListViewMode: 'hierarchy' | 'list' | null;
  caseResolverCaseListSortBy: | 'updated' | 'created' | 'happeningDate' | 'name' | 'status' | 'signature' | 'locked' | 'sent' | null;
  caseResolverCaseListSortOrder: 'asc' | 'desc' | null;
  caseResolverCaseListSearchScope: 'all' | 'name' | 'folder' | 'content' | null;
  caseResolverCaseListFiltersCollapsedByDefault: boolean | null;
  caseResolverCaseListShowNestedContent: boolean | null;
  adminMenuCollapsed: boolean | null;
  adminMenuFavorites: string[] | null;
  adminMenuSectionColors: Record<string, string> | null;
  adminMenuCustomEnabled: boolean | null;
  adminMenuCustomNav: JsonValue | null;
  cmsLastPageId: string | null;
  cmsActiveDomainId: string | null;
  cmsThemeOpenSections: string[];
  cmsThemeLogoWidth: number | null;
  cmsThemeLogoUrl: string | null;
  cmsPreviewEnabled: boolean | null;
  cmsSlideshowPauseOnHoverInEditor: boolean | null;
  createdAt: Date;
  updatedAt: Date;
};

const USER_PREFERENCES_COLLECTION = 'user_preferences';
const USER_PREFERENCES_CACHE_TTL_MS = parsePositiveInt(process.env['USER_PREFERENCES_CACHE_TTL_MS'], 60_000);
const IMMUTABLE_FIELDS = new Set(['id', '_id', 'userId', 'createdAt', 'updatedAt']);

type CachedUserPreferences = { value: UserPreferencesRecord; fetchedAt: number; };
const userPreferencesCache = new Map<string, CachedUserPreferences>();
const userPreferencesInflight = new Map<string, Promise<UserPreferencesRecord>>();

const getCacheKey = (userId: string): string => String(toMongoId(userId));

const getCachedPrefs = (cacheKey: string): UserPreferencesRecord | null => {
  const cached = userPreferencesCache.get(cacheKey);
  if (cached === undefined) return null;
  if (Date.now() - cached.fetchedAt > USER_PREFERENCES_CACHE_TTL_MS) {
    userPreferencesCache.delete(cacheKey); return null;
  }
  return cached.value;
};

const setCachedPrefs = (cacheKey: string, value: UserPreferencesRecord): void => {
  userPreferencesCache.set(cacheKey, { value, fetchedAt: Date.now() });
};

export const peekUserPreferencesCache = (userId: string, options?: { allowStale?: boolean }): UserPreferencesRecord | null => {
  const key = getCacheKey(userId);
  if (options?.allowStale === true) return userPreferencesCache.get(key)?.value ?? null;
  return getCachedPrefs(key);
};

export const warmUserPreferencesCache = (userId: string): void => {
  void getUserPreferences(userId).catch(() => {});
};

export const invalidateUserPreferencesCache = (userId?: string): void => {
  if (userId !== undefined) {
    const key = getCacheKey(userId); userPreferencesCache.delete(key); userPreferencesInflight.delete(key);
    return;
  }
  userPreferencesCache.clear(); userPreferencesInflight.clear();
};

const toUserPreferences = (doc: UserPreferencesDocument): UserPreferencesRecord => ({
  id: String(doc._id), userId: doc.userId,
  productListNameLocale: doc.productListNameLocale ?? 'name_en', productListCatalogFilter: doc.productListCatalogFilter ?? 'all',
  productListCurrencyCode: doc.productListCurrencyCode, productListPageSize: doc.productListPageSize ?? 12,
  productListThumbnailSource: doc.productListThumbnailSource ?? 'file', productListFiltersCollapsedByDefault: doc.productListFiltersCollapsedByDefault ?? true,
  productListShowTriggerRunFeedback: doc.productListShowTriggerRunFeedback ?? true, productListAdvancedFilterPresets: doc.productListAdvancedFilterPresets ?? [],
  productListAppliedAdvancedFilter: doc.productListAppliedAdvancedFilter ?? null, productListAppliedAdvancedFilterPresetId: doc.productListAppliedAdvancedFilterPresetId ?? null,
  productListDraftIconColorMode: doc.productListDraftIconColorMode ?? 'theme', productListDraftIconColor: doc.productListDraftIconColor ?? '#60a5fa',
  aiPathsActivePathId: doc.aiPathsActivePathId ?? null, imageStudioLastProjectId: doc.imageStudioLastProjectId ?? null,
  caseResolverCaseListViewMode: doc.caseResolverCaseListViewMode ?? 'hierarchy', caseResolverCaseListSortBy: doc.caseResolverCaseListSortBy ?? 'updated',
  caseResolverCaseListSortOrder: doc.caseResolverCaseListSortOrder ?? 'desc', caseResolverCaseListSearchScope: doc.caseResolverCaseListSearchScope ?? 'all',
  caseResolverCaseListFiltersCollapsedByDefault: doc.caseResolverCaseListFiltersCollapsedByDefault ?? true, caseResolverCaseListShowNestedContent: doc.caseResolverCaseListShowNestedContent ?? true,
  adminMenuCollapsed: doc.adminMenuCollapsed ?? false, adminMenuFavorites: doc.adminMenuFavorites ?? [],
  adminMenuSectionColors: doc.adminMenuSectionColors ?? {}, adminMenuCustomEnabled: doc.adminMenuCustomEnabled ?? false,
  adminMenuCustomNav: doc.adminMenuCustomNav ?? [], cmsLastPageId: doc.cmsLastPageId ?? null,
  cmsActiveDomainId: doc.cmsActiveDomainId ?? null, cmsThemeOpenSections: doc.cmsThemeOpenSections ?? [],
  cmsThemeLogoWidth: doc.cmsThemeLogoWidth ?? null, cmsThemeLogoUrl: doc.cmsThemeLogoUrl ?? null,
  cmsPreviewEnabled: doc.cmsPreviewEnabled ?? null, cmsSlideshowPauseOnHoverInEditor: doc.cmsSlideshowPauseOnHoverInEditor ?? false,
  createdAt: doc.createdAt.toISOString(), updatedAt: doc.updatedAt.toISOString(),
});

const defaultPreferences = (userId: string): Omit<UserPreferencesRecord, 'id' | 'createdAt' | 'updatedAt'> => ({
  userId, productListNameLocale: 'name_en', productListCatalogFilter: 'all', productListCurrencyCode: 'PLN', productListPageSize: 12,
  productListThumbnailSource: 'file', productListFiltersCollapsedByDefault: true, productListShowTriggerRunFeedback: true,
  productListAdvancedFilterPresets: [], productListAppliedAdvancedFilter: null, productListAppliedAdvancedFilterPresetId: null,
  productListDraftIconColorMode: 'theme', productListDraftIconColor: '#60a5fa', aiPathsActivePathId: null, imageStudioLastProjectId: null,
  caseResolverCaseListViewMode: 'hierarchy', caseResolverCaseListSortBy: 'updated', caseResolverCaseListSortOrder: 'desc',
  caseResolverCaseListSearchScope: 'all', caseResolverCaseListFiltersCollapsedByDefault: true, caseResolverCaseListShowNestedContent: true,
  adminMenuCollapsed: false, adminMenuFavorites: [], adminMenuSectionColors: {}, adminMenuCustomEnabled: false, adminMenuCustomNav: [],
  cmsLastPageId: null, cmsActiveDomainId: null, cmsThemeOpenSections: [], cmsThemeLogoWidth: null, cmsThemeLogoUrl: null,
  cmsPreviewEnabled: false, cmsSlideshowPauseOnHoverInEditor: false,
});

const sanitizeUpdate = (data: Partial<UserPreferencesData>): Record<string, unknown> => {
  const s: Record<string, unknown> = {};
  Object.entries(data).forEach(([k, v]) => { if (v !== undefined && !IMMUTABLE_FIELDS.has(k)) s[k] = v; });
  return s;
};

const isPrefsDoc = (v: unknown): v is UserPreferencesDocument => {
  if (v === null || typeof v !== 'object' || Array.isArray(v)) return false;
  const r = v as Record<string, unknown>;
  return '_id' in r && typeof r['userId'] === 'string' && r['createdAt'] instanceof Date && r['updatedAt'] instanceof Date;
};

export async function getUserPreferences(userId: string): Promise<UserPreferencesRecord> {
  if (process.env['MONGODB_URI'] === undefined || process.env['MONGODB_URI'] === '') throw operationFailedError('MongoDB is not configured.');
  const id = toMongoId(userId); const key = getCacheKey(userId);
  const cached = getCachedPrefs(key); if (cached !== null) return cached;
  const inflight = userPreferencesInflight.get(key); if (inflight !== undefined) return inflight;

  const promise = (async (): Promise<UserPreferencesRecord> => {
    const db = await getMongoDb(); const col = db.collection<UserPreferencesDocument>(USER_PREFERENCES_COLLECTION);
    const doc = await col.findOne({ _id: id });
    if (doc) { const norm = toUserPreferences(doc); setCachedPrefs(key, norm); return norm; }
    const now = new Date(); const document: UserPreferencesDocument = { _id: id, ...defaultPreferences(userId), createdAt: now, updatedAt: now };
    await col.insertOne(document); const norm = toUserPreferences(document); setCachedPrefs(key, norm); return norm;
  })().finally(() => { userPreferencesInflight.delete(key); });

  userPreferencesInflight.set(key, promise); return promise;
}

export async function updateUserPreferences(userId: string, data: Partial<UserPreferencesData>): Promise<UserPreferencesRecord> {
  if (process.env['MONGODB_URI'] === undefined || process.env['MONGODB_URI'] === '') throw operationFailedError('MongoDB is not configured.');
  const key = getCacheKey(userId); const db = await getMongoDb(); const col = db.collection<UserPreferencesDocument>(USER_PREFERENCES_COLLECTION);
  const id = toMongoId(userId); const now = new Date(); const setData = sanitizeUpdate(data);
  const insertDefaults = { _id: id, ...defaultPreferences(userId), createdAt: now } as Record<string, unknown>;
  for (const k of Object.keys(setData)) delete insertDefaults[k];
  const updateDoc: { $set: Record<string, unknown>; $setOnInsert?: Record<string, unknown>; } = { $set: { ...setData, updatedAt: now } };
  if (Object.keys(insertDefaults).length > 0) updateDoc.$setOnInsert = { ...insertDefaults };
  const res = await col.findOneAndUpdate({ _id: id }, updateDoc, { upsert: true, returnDocument: 'after' });
  const updated = res && typeof res === 'object' && 'value' in res ? res.value : res;
  if (isPrefsDoc(updated)) { const norm = toUserPreferences(updated); setCachedPrefs(key, norm); return norm; }
  const fallback = await col.findOne({ _id: id });
  if (fallback === null) throw operationFailedError('Failed to update preferences', undefined, { userId });
  const norm = toUserPreferences(fallback); setCachedPrefs(key, norm); return norm;
}

export async function getOrCreatePreferences(userId: string): Promise<UserPreferencesRecord> {
  return getUserPreferences(userId);
}

import 'server-only';

import { authError } from '@/shared/errors/app-error';
import { readOptionalServerAuthSession } from './optional-server-auth';

export async function assertSettingsManageAccess(): Promise<void> {
  const session = await readOptionalServerAuthSession();
  if (hasAccess(session)) return;

  throw authError('Unauthorized.');
}

function hasAccess(session: any): boolean {
  const isElevated = session?.user?.isElevated ?? false;
  const canManage = session?.user?.permissions?.includes('settings.manage') ?? false;
  return isElevated || canManage;
}

import 'server-only';

import {
  isSensitiveKey,
  REDACTED_VALUE,
  truncateString,
} from '@/shared/lib/observability/log-redaction';
import { logSystemEvent } from '@/shared/lib/observability/system-logger';
import { ErrorSystem } from '@/shared/utils/observability/error-system';


type AuthLogStage = 'start' | 'success' | 'failure';

type AuthLogInput = {
  req: Request;
  action: string;
  stage: AuthLogStage;
  userId?: string | null;
  status?: number;
  outcome?: string;
  body?: unknown;
  extra?: Record<string, unknown>;
};

const MAX_STRING = 2000;
const MAX_DEPTH = 4;
const MAX_ARRAY = 20;

const safeHeaderKeys = new Set([
  'content-type',
  'user-agent',
  'origin',
  'referer',
  'x-forwarded-for',
  'x-real-ip',
  'x-request-id',
]);

const AUTH_LOGGING_ENABLED = process.env['AUTH_LOGGING'] === 'true';

const getClientIp = (req: Request): string | null => {
  const forwarded = req.headers.get('x-forwarded-for');
  if (forwarded !== null) {
    const first = forwarded.split(',')[0];
    if (first !== undefined && first !== '') return first.trim();
  }
  const real = req.headers.get('x-real-ip');
  if (real !== null) return real;
  return null;
};

const redactObject = (value: Record<string, unknown>, depth: number): Record<string, unknown> => {
  const out: Record<string, unknown> = {};
  Object.entries(value).forEach(([key, val]: [string, unknown]) => {
    if (isSensitiveKey(key)) {
      out[key] = REDACTED_VALUE;
    } else {
      out[key] = redactValue(val, depth + 1);
    }
  });
  return out;
};

const redactValue = (value: unknown, depth: number): unknown => {
  if (depth > MAX_DEPTH) return '[Truncated]';
  if (typeof value === 'string') return truncateString(value, MAX_STRING);
  if (typeof value === 'number' || typeof value === 'boolean' || value === null) return value;
  if (Array.isArray(value)) {
    return value.slice(0, MAX_ARRAY).map((item: unknown) => redactValue(item, depth + 1));
  }
  if (typeof value === 'object' && value !== null) {
    return redactObject(value as Record<string, unknown>, depth);
  }
  return '[Unknown]';
};

const redactBody = (body: unknown): Record<string, unknown> | null => {
  if (body === undefined || body === null || body === false) return null;
  const redacted = redactValue(body, 0);
  if (redacted !== null && typeof redacted === 'object' && !Array.isArray(redacted)) {
    return redacted as Record<string, unknown>;
  }
  return { value: redacted };
};

const extractHeaders = (req: Request): Record<string, string> => {
  const result: Record<string, string> = {};
  req.headers.forEach((value: string, key: string) => {
    if (!safeHeaderKeys.has(key.toLowerCase())) return;
    result[key] = truncateString(value, 400);
  });
  return result;
};

const buildAuthContext = (input: AuthLogInput, url: URL): Record<string, unknown> => {
  const context: Record<string, unknown> = {
    stage: input.stage,
    path: url.pathname,
    method: input.req.method,
    ip: getClientIp(input.req),
    headers: extractHeaders(input.req),
  };

  if (typeof input.outcome === 'string' && input.outcome !== '') {
    context['outcome'] = input.outcome;
  }
  if (typeof input.status === 'number') {
    context['status'] = input.status;
  }
  if (input.body !== undefined && input.body !== null) {
    context['body'] = redactBody(input.body);
  }
  if (input.extra !== undefined && input.extra !== null) {
    context['extra'] = redactValue(input.extra, 0);
  }

  return context;
};

export async function logAuthEvent(input: AuthLogInput): Promise<void> {
  if (!AUTH_LOGGING_ENABLED) return;
  try {
    const url = new URL(input.req.url);
    const context = buildAuthContext(input, url);

    await logSystemEvent({
      level: input.stage === 'failure' ? 'warn' : 'info',
      message: `${input.action}.${input.stage}`,
      source: input.action,
      request: input.req,
      userId: input.userId ?? null,
      ...(input.status !== undefined ? { statusCode: input.status } : {}),
      context,
    });
  } catch (error) {
    ErrorSystem.captureException(error).catch(() => {});
  }
}
